head.script:
/**
 * 화 면 명 : 내부거래상세
 * 메뉴경로 : 회계/관리회계/실적관리/내부거래관리/
 * ASIS경로 : /debis/dongwon-debis-engine/src/main/webapp/ac/co/rsltsmgnt/internaltxnmgnt/co_401_02_02p.jsp
 * 작 성 자 : 배기원
 * 작 업 일 : 2026-01-05
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅(UDC), 그리드(데이터리스트)
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 * 참고사항
 *    1. login정보 확인 필요 
 *     ☞  $c.data.getMemInfo() 처리
 *    2. [해결]<%@ page import="dbl.ac.am.constants.ACConstants" %> 상수가져오는건 공통에서 글로벌 상수로 변경할 듯. 
 *    3. 상수값 가져오는거 어떻게 할지? DGlobalValue.java 이런거 있을때마다 개발자가 DGlobalValue.js로 변경해서 올려야 하나?
 *    4. ☏ $c.gus.cfJobCloseYN 공통함수 없음
 *    ☞ 2025-12-22 공통개발됨(udc_comChkRes)
 *    5. 2026-05-12 T-7960 결함 수정 건(data:ds_txn.ctrtClntNm >> AS-IS 버그인데, 결함으로 인한 동기화 처리)
 * 수정이력 :
 *    - 2026-01-05      배기원    최초작성
 */
//hidden 값
scwin.hid_txnDt = "";    //거래일자
scwin.wrkNo     = "";    //작업구분코드
scwin.fromDate  = "";    //년월
scwin.isClose   = "";    //마감체크(tobe 추가)
scwin.today     = "";    //오늘날짜

scwin.memJson;
scwin.vLoginCoCd;       //소속자회사
scwin.vLoginCoClsCd;    //회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd;   //사용자소속구분코드
scwin.isSubCompany;

/**
 * TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
 */
scwin.onpageload = function() {
    scwin.memJson = $c.data.getMemInfo();
    scwin.vLoginCoCd     = $c.gus.cfIsNull(scwin.memJson["coCd"]) ? "" : scwin.memJson["coCd"];                     //소속자회사
    scwin.vLoginCoClsCd  = $c.gus.cfIsNull(scwin.memJson["coClsCd"]) ? "" : scwin.memJson["coClsCd"];               //회계_회사구분('CO035' : 0:동부 EXPRESS)
    scwin.vUserHomeClsCd = $c.gus.cfIsNull(scwin.memJson["userHomeClsCd"]) ? "" : scwin.memJson["userHomeClsCd"];   //사용자소속구분코드
    scwin.isSubCompany   = false;

    scwin.today = $c.date.getServerDateTime();
};


/**
 * 초기세팅(TOBE 그리드, 총건수)
 */
scwin.setInit = function() {
    $c.gus.cfDisableKeyData();
    $c.gus.cfDisableObjects([udc_pchsAcctDeptCd, udc_reqClntNo]);
    $c.gus.cfDisableObjects([btn_save, btn_delete, btn_update]);
    ds_txn.reform();
    ds_txn.removeAll();
    scwin.f_clear();
};

/**
 * UDC값 초기화(scwin.onpageload 이후 세팅됨)
 */
scwin.onUdcCompleted = async function () {
    //타이틀 추가
    $c.data.setPopupTitle("내부거래상세조회");

    await scwin.f_HeaderCreate();
    ed_schBilgNo.setValue($c.data.getParameter("internalTxnBilgNo"));
    await scwin.f_Retrieve();
    ed_schBilgNo.focus();
    // $c.gus.cfDisableKeyData();
    // //UDC disable
    // $c.gus.cfDisableObjects([udc_pchsAcctDeptCd, udc_reqClntNo]);

    let ret;
    ret = await scwin.f_JobCloseYN2();
    // 해당 거래일자가 마감이면 버튼 비활성화 시킨다.
    if (!ret) {
        $c.gus.cfDisableObjects([btn_save, btn_delete, btn_update]);
    }
    //내부거래상태코드 상태가 등록이 아니면 버튼 비활성화시킨다.
    if (ds_txn.getCellData(0, "internalTxnStsCd") != "0") {
        $c.gus.cfDisableObjects([btn_save, btn_delete, btn_update]);
    } else {
        $c.gus.cfEnableObjects([btn_save, btn_delete, btn_update]);
    }
};


/**
* 조회버튼
*/
scwin.f_Retrieve = async function() {
    let ret;
    ret = await $c.gus.cfValidate([tb_search]);
    if (!ret) {
        return false;
    }
    scwin.setInit();
    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function(e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    if (ds_txn.getRowCount() > 0) {
        scwin.f_fill();
        ds_txn.setRowPosition(0, event);
        scwin.hid_txnDt = ica_txnDt.getValue().trim().substring(0,6);

        // 내부거래상태코드 상태가 등록인 경우 활성화
        if (ds_txn.getCellData(0, "internalTxnStsCd") == "0") {
            $c.gus.cfEnableObjects([btn_save, btn_delete, btn_update]);
        }
    } else {
        //조회결과가 존재하지 않습니다
        $c.gus.cfAlertMsg(MSG_CM_WRN_002); 
    }
};

scwin.sbm_retrieve_submiterror = function(e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg)
};

/**
 * 조회 데이터셋 헤더 생성
 * TOBE 사업영역 가져오는걸로 사용
 */
scwin.f_HeaderCreate = async function() {
    // var GAUCE_DATASET_HEADER = "bilgNo:STRING";
    // ds_search.SetDataHeader(GAUCE_DATASET_HEADER);
    // ds_search.insertRow();

    ds_bizDom.removeAll();
    await $c.sbm.execute(sbm_bizDom, {"useYn":1});
    ds_bizDom.reform();
};


/**
 * 저장버튼
 */
scwin.f_Save = async function() {
    let ret;
    // 마감여부 확인
    ret = await scwin.f_JobCloseYN();
    if(!ret) {
        return false;
    }

//    if (ds_txn.isUpdated == false) {
    // 변경된 사항이 있는지 확인.
    if (ds_txn.getModifiedIndex().length < 1) {
        // MSG_CM_ERR_001   = "@은(는) 변경된 사항이 없습니다."
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["내부거래상세정보"]);
        return;
    }

    //Mandatory 항목이 누락하지 않았는지 체크한다.
    ret = await $c.gus.cfValidate([tb_bilg]);
    if (!ret) {
        return false;
    }

    if (await $c.win.confirm(MSG_CM_CRM_001) ) {
        $c.sbm.execute(sbm_save); 
    }
};

scwin.sbm_save_submitdone = function(e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        $c.gus.cfAlertMsg(MSG_CM_INF_001);
        $c.gus.cfDisableKeyData();
        $c.gus.cfDisableBtn([btn_save]);       
        //UDC disable
        $c.gus.cfDisableObjects([udc_pchsAcctDeptCd, udc_reqClntNo]);
        scwin.f_Retrieve();
    }
};

scwin.sbm_save_submiterror = function(e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};

/**
 * 수정버튼
 */
scwin.f_Update = function() {
    $c.gus.cfDisableKey();
    $c.gus.cfEnableObjects([udc_pchsAcctDeptCd, udc_reqClntNo]);
    $c.gus.cfDisableBtn([btn_update]);
};


/**
 * 삭제버튼
 */
scwin.f_Delete = async function() {
    let ret;
    // 마감여부 확인
    ret = await scwin.f_JobCloseYN();
    if(!ret) {
        return false;
    }

    // if (ds_txn.getRowCount() == 0 || ds_txn.RowStatus(ds_txn.getRowPosition) == 1) {
    if (ds_txn.getRowCount() == 0) {
        await $c.win.alert("조회후 삭제가능합니다.");
        return;
    } else {
        if (await $c.win.confirm(MSG_CM_CRM_004)) {
            // ds_txn.deleteRow(ds_txn.getRowPosition());
            // $c.sbm.execute(sbm_deleteTxn);
            ds_txn.modifyRowStatus(0, "D");
            $c.sbm.execute(sbm_delete); 
        }
    }
};

scwin.sbm_delete_submitdone = function(e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        ed_schBilgNo.setValue("");
        scwin.setInit();
        $c.gus.cfDisableKeyData();
        $c.gus.cfDisableObjects([udc_pchsAcctDeptCd, udc_reqClntNo]);
        $c.gus.cfAlertMsg(MSG_CM_INF_004);
        ed_schBilgNo.focus();
    }
};

scwin.sbm_deletee_submiterror = function(e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};

